#!/usr/bin/env node
/**
 * Make clips-service.vercel.app permanently redirect to https://clipservice.app
 * so the team alias never sends users into the auth-cookie 403 trap.
 * Per-deployment URLs (clips-service-<hash>-...) cannot be redirected this way -
 * they're auto-generated by Vercel and only intended for inspecting builds.
 */
import { readFileSync, existsSync } from "node:fs";
import { resolve, dirname } from "node:path";
import { fileURLToPath } from "node:url";

const root = resolve(dirname(fileURLToPath(import.meta.url)), "..");
function loadDotEnv(name) {
  const p = resolve(root, name);
  if (!existsSync(p)) return;
  for (const line of readFileSync(p, "utf8").split("\n")) {
    const t = line.trim(); if (!t || t.startsWith("#")) continue;
    const eq = t.indexOf("="); if (eq < 0) continue;
    const k = t.slice(0, eq).trim(); let v = t.slice(eq + 1).trim();
    if ((v.startsWith('"') && v.endsWith('"')) || (v.startsWith("'") && v.endsWith("'"))) v = v.slice(1, -1);
    if (process.env[k] === undefined || process.env[k] === "") process.env[k] = v;
  }
}
loadDotEnv(".env"); loadDotEnv(".env.local");

const token = process.env.VERCEL_TOKEN?.trim();
const projectId = "prj_LUt039Hz0ztnvgmqD6D6TtibkDYY";
const aliasDomain = "clips-service.vercel.app";
const target = "clipservice.app";

async function call(method, path, body) {
  const res = await fetch(`https://api.vercel.com${path}`, {
    method,
    headers: { Authorization: `Bearer ${token}`, "content-type": "application/json" },
    body: body ? JSON.stringify(body) : undefined,
  });
  const text = await res.text();
  let json = null; try { json = text ? JSON.parse(text) : null; } catch (_e) {}
  return { status: res.status, ok: res.ok, body: json ?? text };
}

const before = await call("GET", `/v9/projects/${projectId}/domains/${aliasDomain}`);
console.log("BEFORE:", before.status, JSON.stringify(before.body).slice(0, 300));

const patch = await call("PATCH", `/v9/projects/${projectId}/domains/${aliasDomain}`, {
  redirect: target,
  redirectStatusCode: 308,
});
console.log("\nPATCH:", patch.status, JSON.stringify(patch.body).slice(0, 400));

const after = await call("GET", `/v9/projects/${projectId}/domains/${aliasDomain}`);
console.log("\nAFTER:", after.status, JSON.stringify(after.body).slice(0, 300));
